oxy_webhelp_navlinks = {"azr_rcv_private_service_endpoints-d30753e19511":{"topics":[{"title":"Configuring a private endpoint for RCV archiving of Azure workloads","shortdesc":"<p class=\"shortdesc\">Configure a private endpoint between the Exocompute virtual network and the Rubrik         Cloud Vault storage account to restrict archival traffic to private         connectivity.<\/p>","href":"saas\/azr_rcv_configuring_private_endpoint.html","attributes":{"data-id":"azr_rcv_configuring_private_endpoint"},"menu":{"hasChildren":false},"tocID":"azr_rcv_configuring_private_endpoint-d30753e19522","topics":[]},{"title":"Configuring a service endpoint for RCV archiving of Azure workloads","shortdesc":"<p class=\"shortdesc\">Configure a service endpoint on the Exocompute subnet to keep RCV archival traffic         on the Azure backbone and restrict the RCV storage account to the specified virtual         network.<\/p>","href":"saas\/azr_rcv_configuring_service_endpoint.html","attributes":{"data-id":"azr_rcv_configuring_service_endpoint"},"menu":{"hasChildren":false},"tocID":"azr_rcv_configuring_service_endpoint-d30753e19533","topics":[]},{"title":"Removing a private or service endpoint from an RCV archival location","shortdesc":"<p class=\"shortdesc\">Removing a private or service endpoint from an RCV archival location requires         coordination with Rubrik through a support case. Self-service removal from <span class=\"ph\">RSC<\/span> is not available for RCV archiving of cloud-native workloads.<\/p>","href":"saas\/azr_rcv_removing_endpoint.html","attributes":{"data-id":"azr_rcv_removing_endpoint"},"menu":{"hasChildren":false},"tocID":"azr_rcv_removing_endpoint-d30753e19544","topics":[]}]}};